// And groups predicates with the AND operator between them.
func And(predicates ...predicate.KnowledgeRelationship) predicate.KnowledgeRelationship {
	return predicate.KnowledgeRelationship(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.KnowledgeRelationship) predicate.KnowledgeRelationship {
	return predicate.KnowledgeRelationship(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.KnowledgeRelationship) predicate.KnowledgeRelationship {
	return predicate.KnowledgeRelationship(sql.NotPredicates(p))
}
